sql:
SELECT SUM(budget) AS total_budget
FROM studies
WHERE description LIKE '%AI%';

SELECT studies.study_title, researchers.researcher_name, studies.end_date
FROM studies
JOIN researchers ON studies.researcher_id = researchers.researcher_id;

SELECT AVG(budget) AS average_budget_above_avg
FROM studies
WHERE budget > (SELECT AVG(budget) FROM studies);

SELECT s.study_title, st.study_type_name
FROM studies s
INNER JOIN study_types st ON s.study_type = st.study_type_id;
